"use client";

import React, { useState } from "react";
import Header from "@/components/Header";
import PromoBanners from "@/components/PromoBanners";
import ProductCard from "@/components/ProductCard";
import CartSidebar from "@/components/CartSidebar";
import { products } from "@/components/data";

export interface CartItem {
 id: number;
 name: string;
 price: number;
 oldPrice?: number;
 quantity: number;
 imageColor: string;
}

export default function Home() {
 const [cart, setCart] = useState<CartItem[]>([]);

 const addToCart = (product: any) => {
  setCart((prevCart) => {
   const existingItem = prevCart.find((item) => item.id === product.id);
   if (existingItem) {
    return prevCart.map((item) =>
     item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
    );
   }
   return [...prevCart, { ...product, quantity: 1 }];
  });
 };

 const updateQuantity = (id: number, delta: number) => {
  setCart((prevCart) => {
   return prevCart
    .map((item) =>
     item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
    )
    .filter((item) => item.quantity > 0);
  });
 };

 const total = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

 return (
  <div className="min-h-screen bg-white text-black font-sans">
   <Header />

   <main className="pt-20">
    <div className="flex min-h-[calc(100vh-80px)]">
     {/* Main Content Area */}
     <div className="flex-1 overflow-y-auto">
      <PromoBanners />

      <section className="px-8 md:px-14 py-8 max-w-[1440px] mx-auto pb-32">
       <div className="flex items-center justify-between mb-8">
        <h2 className="text-[32px] font-extrabold tracking-tight">Товары</h2>
       </div>

       <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 xl:grid-cols-5 gap-x-6 gap-y-12">
        {products.map((product) => (
         <ProductCard
          key={product.id}
          {...product}
          onAdd={() => addToCart(product)}
         />
        ))}

        {/* Special "More" card */}
        <div className="group cursor-pointer">
         <div className="relative aspect-square rounded-[24px] bg-[#F7F7F7] flex flex-col items-center justify-center transition-all group-hover:shadow-md">
          <div className="text-center">
           <p className="text-[13px] font-extrabold mb-3">Больше</p>
           <div className="w-10 h-10 rounded-full bg-white shadow-sm flex items-center justify-center mx-auto group-hover:scale-110 transition-transform">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
             <path d="M5 12h14M12 5l7 7-7 7" />
            </svg>
           </div>
          </div>
         </div>
        </div>
       </div>
      </section>
     </div>

     {/* Sidebar Area - Hidden on small screens or just shown on desktop as in screenshot */}
     <div className="hidden lg:block w-[420px] sticky top-20 h-[calc(100vh-80px)]">
      <CartSidebar
       cart={cart}
       onUpdateQuantity={updateQuantity}
       total={total}
      />
     </div>
    </div>
   </main>
  </div>
 );
}
