import React from 'react';
import { SearchIcon } from './icons';

const Header = () => {
 return (
  <header className="fixed top-0 left-0 right-0 z-50 flex h-20 items-center bg-white px-8 md:px-14">
   <div className="flex w-full items-center justify-between gap-8 max-w-[1440px] mx-auto">
    <div className="flex items-center">
     <div className="text-[17px] font-extrabold tracking-[0.05em] text-black uppercase leading-[1.1]">
      Смысл<br />Есть
     </div>
    </div>

    <div className="flex-1 max-w-[600px]">
     <div className="relative group">
      <span className="absolute left-5 top-1/2 -translate-y-1/2 text-[#999]">
       <SearchIcon size={18} />
      </span>
      <input
       type="text"
       placeholder="Search for croissants, sourdough..."
       className="h-12 w-full rounded-full bg-[#F4F4F6] px-14 text-[14px] text-black outline-none transition-all placeholder:text-[#999] focus:bg-[#EBEBEB]"
      />
     </div>
    </div>


    <div className="flex items-center">
     <div className="h-11 w-11 rounded-full bg-[#F4F4F6] flex items-center justify-center">
      <div className="h-full w-full rounded-full bg-[#F4F4F6] border border-[#EBEBEB]" />
     </div>
    </div>
   </div>
  </header>
 );
};

export default Header;
