import React from 'react';
import { CartItem } from '@/app/page';

interface CartSidebarProps {
 cart: CartItem[];
 onUpdateQuantity: (id: number, delta: number) => void;
 total: number;
}

const CartSidebar: React.FC<CartSidebarProps> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <aside className="w-full h-full bg-white p-6 md:p-8 flex flex-col border-l border-[#F0F0F0] overflow-y-auto">
   <h2 className="text-[24px] font-extrabold mb-8">Корзина</h2>
   <div className="mb-8 group cursor-pointer shrink-0">
    <div className="flex items-center gap-1">
     <h3 className="text-[14px] font-[800]">улица Академика Янгеля</h3>
     <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-[#999] group-hover:translate-y-0.5 transition-transform">
      <path d="m6 9 6 6 6-6" />
     </svg>
    </div>
    <div className="mt-2 inline-flex items-center px-2 py-0.5 bg-[#F4F4F6] rounded-md">
     <p className="text-[11px] font-bold text-black px-1">Доставка 15 минут</p>
    </div>
   </div>

   {/* Cart Items */}
   <div className="space-y-6 mb-8 flex-1">
    {cart.length === 0 ? (
     <p className="text-[13px] text-[#999] text-center mt-10">Ваша корзина пуста</p>
    ) : (
     cart.map((item) => (
      <div key={item.id} className="flex gap-4">
       <div className="w-14 h-14 rounded-xl bg-[#F7F7F7] flex items-center justify-center overflow-hidden border border-[#F0F0F0] p-2 shrink-0">
        <div className={`w-full h-full rounded-lg opacity-80 ${item.imageColor}`} />
       </div>
       <div className="flex-1 min-w-0">
        <h4 className="text-[12px] font-semibold leading-[1.3] text-black truncate">{item.name}</h4>
        <p className="text-[11px] text-[#999] mt-0.5">1 шт</p>

        <div className="flex items-center justify-between mt-3">
         <div className="flex items-center gap-4 bg-[#F4F4F6] rounded-full px-3 py-1">
          <button
           onClick={() => onUpdateQuantity(item.id, -1)}
           className="text-[#999] hover:text-black font-bold"
          >
           −
          </button>
          <span className="text-[13px] font-bold">{item.quantity}</span>
          <button
           onClick={() => onUpdateQuantity(item.id, 1)}
           className="text-[#999] hover:text-black font-bold"
          >
           +
          </button>
         </div>
         <div className="text-right">
          <div className="flex items-center gap-1.5 justify-end">
           {item.oldPrice && (
            <p className="text-[11px] text-[#999] line-through">{item.oldPrice}</p>
           )}
           <p className="text-[14px] font-extrabold text-[#333]">{item.price * item.quantity} ₽</p>
          </div>
         </div>
        </div>
       </div>
      </div>
     ))
    )}
   </div>

   {/* Summary and Button */}
   <div className="pt-8 mt-auto shrink-0 border-t border-[#F0F0F0]">
    <div className="flex items-baseline justify-between mb-6">
     <span className="text-[13px] text-[#999] font-medium">Итого</span>
     <span className="text-[28px] font-extrabold text-black">{total} ₽</span>
    </div>

    <button
     disabled={cart.length === 0}
     className="w-full py-4 bg-[#AE713F] text-white rounded-[20px] font-bold text-[14px] shadow-lg shadow-[#AE713F]/20 hover:bg-[#965E32] transition-all hover:scale-[0.99] active:scale-95 disabled:opacity-50 disabled:grayscale disabled:cursor-not-allowed"
    >
     Продолжить
    </button>
   </div>
  </aside>
 );
};

export default CartSidebar;
